(window.webpackJsonp=window.webpackJsonp||[]).push([[1071],{1008:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">edges</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findMinHeightTrees = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, edges</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(n===<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">return</span> [<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-keyword\\">let</span> graph=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span>[])\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [v,w] <span class=\\"hljs-keyword\\">of</span> edges){\\n    graph[v].push(w)\\n    graph[w].push(v)\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> leaf=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;graph.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(graph[i].length===<span class=\\"hljs-number\\">1</span>){\\n      leaf.push(i)\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">while</span>(n&gt;<span class=\\"hljs-number\\">2</span>){\\n    <span class=\\"hljs-keyword\\">let</span> len=leaf.length\\n    n-=len\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> v=leaf.shift()\\n      <span class=\\"hljs-keyword\\">let</span> nxtV=graph[v].pop()\\n      <span class=\\"hljs-keyword\\">let</span> adj=graph[nxtV]\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;adj.length;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(adj[j]===v)adj.splice(j,<span class=\\"hljs-number\\">1</span>)\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(adj.length===<span class=\\"hljs-number\\">1</span>)leaf.push(nxtV)\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> leaf\\n};\\n</code></pre>\\n"],"titleSlug":"minimum-height-trees","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u6211\u4eec\u8981\u627e\u51fa\u4e00\u68f5\u6811\u7684\u6700\u5c0f\u9ad8\u5ea6\u7684\u6839\u8282\u70b9\uff0c\u5176\u5b9e\u5c31\u662f\u8981\u627e\u5230\u6700\u4e2d\u5fc3\u7684<code>1</code>\u4e2a\u6216\u8005<code>2</code>\u4e2a\u70b9\u3002</p>\\n<p>\u53ef\u4ee5\u5148\u5047\u8bbe\uff0c\u4e00\u6761\u76f4\u7ebf\u7684\u8def\u5f84\uff0c\u6211\u4eec\u5e94\u8be5\u5982\u4f55\u627e\u4e2d\u5fc3\u70b9\uff0c\u4e00\u4e2a\u5f88\u7b80\u5355\u7684\u65b9\u6cd5\uff0c\u76f4\u7ebf\u4e24\u7aef\u4e24\u4e2a\u6307\u9488\uff0c\u5404\u81ea\u5f80\u4e2d\u95f4\u9760\u8fd1\uff0c\u5f532\u4e2a\u6307\u9488\u76f8\u9047\uff0c\\n\u8bf4\u660e\u627e\u5230\u4e86\u4e2d\u5fc3\u70b9\u3002</p>\\n<p><code>\u6811</code>\u540c\u6837\u5982\u6b64\uff0c\u6211\u4eec\u9996\u5148\u627e\u5230<strong>\u53ea\u67091\u4e2a\u90bb\u63a5\u70b9</strong>\u7684\u8282\u70b9\uff0c\u7136\u540e\u901a\u8fc7\u4e0d\u65ad\u5220\u9664\uff0c\u627e\u51fa\u5b83\u4eec\u7684\u4e0b\u4e00\u4e2a\u53ea\u67091\u4e2a\u90bb\u63a5\u70b9\u7684\u8282\u70b9\uff0c\u76f4\u5230\u6700\u540e\u7684\u4e00\u4e2a\u6216\u8005\u4e24\u4e2a\u8282\u70b9\u3002</p>\\n","content":"<p>\u6811\u662f\u4e00\u4e2a\u65e0\u5411\u56fe\uff0c\u5176\u4e2d\u4efb\u4f55\u4e24\u4e2a\u9876\u70b9\u53ea\u901a\u8fc7\u4e00\u6761\u8def\u5f84\u8fde\u63a5\u3002 \u6362\u53e5\u8bdd\u8bf4\uff0c\u4e00\u4e2a\u4efb\u4f55\u6ca1\u6709\u7b80\u5355\u73af\u8def\u7684\u8fde\u901a\u56fe\u90fd\u662f\u4e00\u68f5\u6811\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u68f5\u5305\u542b\xa0<code>n</code>\xa0\u4e2a\u8282\u70b9\u7684\u6811\uff0c\u6807\u8bb0\u4e3a\xa0<code>0</code>\xa0\u5230\xa0<code>n - 1</code> \u3002\u7ed9\u5b9a\u6570\u5b57\xa0<code>n</code>\xa0\u548c\u4e00\u4e2a\u6709 <code>n - 1</code> \u6761\u65e0\u5411\u8fb9\u7684 <code>edges</code>\xa0\u5217\u8868\uff08\u6bcf\u4e00\u4e2a\u8fb9\u90fd\u662f\u4e00\u5bf9\u6807\u7b7e\uff09\uff0c\u5176\u4e2d <code>edges[i] = [a<sub>i</sub>, b<sub>i</sub>]</code> \u8868\u793a\u6811\u4e2d\u8282\u70b9 <code>a<sub>i</sub></code> \u548c <code>b<sub>i</sub></code> \u4e4b\u95f4\u5b58\u5728\u4e00\u6761\u65e0\u5411\u8fb9\u3002</p>\\n\\n<p>\u53ef\u9009\u62e9\u6811\u4e2d\u4efb\u4f55\u4e00\u4e2a\u8282\u70b9\u4f5c\u4e3a\u6839\u3002\u5f53\u9009\u62e9\u8282\u70b9 <code>x</code> \u4f5c\u4e3a\u6839\u8282\u70b9\u65f6\uff0c\u8bbe\u7ed3\u679c\u6811\u7684\u9ad8\u5ea6\u4e3a <code>h</code> \u3002\u5728\u6240\u6709\u53ef\u80fd\u7684\u6811\u4e2d\uff0c\u5177\u6709\u6700\u5c0f\u9ad8\u5ea6\u7684\u6811\uff08\u5373\uff0c<code>min(h)</code>\uff09\u88ab\u79f0\u4e3a <strong>\u6700\u5c0f\u9ad8\u5ea6\u6811</strong> \u3002</p>\\n\\n<p>\u8bf7\u4f60\u627e\u5230\u6240\u6709\u7684 <strong>\u6700\u5c0f\u9ad8\u5ea6\u6811</strong> \u5e76\u6309 <strong>\u4efb\u610f\u987a\u5e8f</strong> \u8fd4\u56de\u5b83\u4eec\u7684\u6839\u8282\u70b9\u6807\u7b7e\u5217\u8868\u3002</p>\\n\u6811\u7684 <strong>\u9ad8\u5ea6</strong> \u662f\u6307\u6839\u8282\u70b9\u548c\u53f6\u5b50\u8282\u70b9\u4e4b\u95f4\u6700\u957f\u5411\u4e0b\u8def\u5f84\u4e0a\u8fb9\u7684\u6570\u91cf\u3002\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/01/e1.jpg\\" style=\\"width: 800px; height: 213px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 4, edges = [[1,0],[1,2],[1,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5982\u56fe\u6240\u793a\uff0c\u5f53\u6839\u662f\u6807\u7b7e\u4e3a 1 \u7684\u8282\u70b9\u65f6\uff0c\u6811\u7684\u9ad8\u5ea6\u662f 1 \uff0c\u8fd9\u662f\u552f\u4e00\u7684\u6700\u5c0f\u9ad8\u5ea6\u6811\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/01/e2.jpg\\" style=\\"width: 800px; height: 321px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 6, edges = [[3,0],[3,1],[3,2],[3,4],[5,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>[3,4]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 1, edges = []\\n<strong>\u8f93\u51fa\uff1a</strong>[0]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 2, edges = [[0,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[0,1]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<ul>\\n</ul>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= n <= 2 * 10<sup>4</sup></code></li>\\n\\t<li><code>edges.length == n - 1</code></li>\\n\\t<li><code>0 <= a<sub>i</sub>, b<sub>i</sub> < n</code></li>\\n\\t<li><code>a<sub>i</sub> != b<sub>i</sub></code></li>\\n\\t<li>\u6240\u6709 <code>(a<sub>i</sub>, b<sub>i</sub>)</code> \u4e92\u4e0d\u76f8\u540c</li>\\n\\t<li>\u7ed9\u5b9a\u7684\u8f93\u5165 <strong>\u4fdd\u8bc1</strong> \u662f\u4e00\u68f5\u6811\uff0c\u5e76\u4e14 <strong>\u4e0d\u4f1a\u6709\u91cd\u590d\u7684\u8fb9</strong></li>\\n</ul>\\n","title":"310. \u6700\u5c0f\u9ad8\u5ea6\u6811","relatedTags":["\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22","\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"310"}')}}]);